/**
 * Generate Asana firewall config.
 *
 * Data source: https://developers.asana.com/docs/authentication
 *
 * Asana is a project management platform.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.asana.com/docs/authentication";
// OAuth access token; format not publicly documented
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe00";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Asana API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:asana",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const asanaFirewall = {",
    '  name: "asana",',
    '  description: "Asana API",',
    "  placeholders: {",
    `    ASANA_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://app.asana.com/api",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.ASANA_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Asana firewall config...");
  const ts = generateTypeScript();
  writeOutput("asana", ts, import.meta.dirname);
}
